VkDevice device = VK_NULL_HANDLE;
uint32_t bindInfoCount = 0;
VkBindAccelerationStructureMemoryInfoNV bindInfos = {};
bindInfos.sType = VK_STRUCTURE_TYPE_BIND_ACCELERATION_STRUCTURE_MEMORY_INFO_NV;

VkResult result = vkBindAccelerationStructureMemoryNV(
    device,
    bindInfoCount,
    &bindInfos
);

if (result == VK_SUCCESS) {
    // تمت العملية بنجاح ويمكن متابعة العمل بعد vkBindAccelerationStructureMemoryNV
} else {
    // عالج رمز الخطأ أو أعد تهيئة الموارد المطلوبة
}

// ربط الذاكرة بالمخزن
VkMemoryRequirements memRequirements;
vkGetBufferMemoryRequirements(device, buffer, &memRequirements);

VkMemoryAllocateInfo allocInfo = {};
allocInfo.sType = VK_STRUCTURE_TYPE_MEMORY_ALLOCATE_INFO;
allocInfo.allocationSize = memRequirements.size;
allocInfo.memoryTypeIndex = findMemoryType(memRequirements.memoryTypeBits, VK_MEMORY_PROPERTY_HOST_VISIBLE_BIT);

VkDeviceMemory memory;
vkAllocateMemory(device, &allocInfo, nullptr, &memory);
vkBindBufferMemory(device, buffer, memory, 0);

